package com.example.sso.controller;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;

import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.Map;
import java.util.Set;

@Controller
public class LogoutController {

    // Allowlist of permitted redirect destinations
    private static final Set<String> ALLOWED_REDIRECT_DOMAINS = Set.of(
            "app1.example.com",
            "app2.example.com",
            "portal.example.com",
            "www.example.com"
    );

    // Server-side route identifiers mapped to actual URLs
    // Instead of accepting arbitrary URLs, clients pass a route key like "app1-home"
    private static final Map<String, String> ROUTE_IDENTIFIERS = Map.of(
            "app1-home", "https://app1.example.com/home",
            "app1-login", "https://app1.example.com/login",
            "app2-home", "https://app2.example.com/home",
            "app2-login", "https://app2.example.com/login",
            "portal-home", "https://portal.example.com/dashboard",
            "portal-login", "https://portal.example.com/login"
    );

    private static final String DEFAULT_REDIRECT_URL = "https://www.example.com/logged-out";

    @GetMapping("/logout")
    public void logoutGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        performLogout(request, response);
    }

    @PostMapping("/logout")
    public void logoutPost(HttpServletRequest request, HttpServletResponse response) throws IOException {
        performLogout(request, response);
    }

    private void performLogout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        // Invalidate the session
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }

        // Determine the redirect URL safely
        String redirectUrl = resolveRedirectUrl(request.getParameter("next"));

        response.sendRedirect(redirectUrl);
    }

    /**
     * Resolves the redirect URL using two strategies:
     * 1. First, check if the 'next' parameter is a known server-side route identifier.
     * 2. If not, validate it against the allowlist of permitted domains.
     * 3. If neither matches, fall back to the default redirect URL.
     */
    private String resolveRedirectUrl(String nextParam) {
        if (nextParam == null || nextParam.isBlank()) {
            return DEFAULT_REDIRECT_URL;
        }

        String trimmed = nextParam.trim();

        // Strategy 1: Check if it's a server-side route identifier
        String routeUrl = ROUTE_IDENTIFIERS.get(trimmed);
        if (routeUrl != null) {
            return routeUrl;
        }

        // Strategy 2: Validate the URL against the allowlist
        if (isAllowedRedirectUrl(trimmed)) {
            return trimmed;
        }

        // Fallback to default
        return DEFAULT_REDIRECT_URL;
    }

    /**
     * Validates that the given URL is on the allowlist of permitted redirect domains.
     * Prevents open redirect vulnerabilities by:
     * - Ensuring the URL uses HTTPS
     * - Ensuring the host is in the allowed domains set
     * - Rejecting URLs with userinfo (e.g., https://evil.com@allowed.com)
     * - Rejecting malformed URLs
     */
    private boolean isAllowedRedirectUrl(String url) {
        try {
            URI uri = new URI(url);

            // Must be an absolute URL with https scheme
            if (!"https".equalsIgnoreCase(uri.getScheme())) {
                return false;
            }

            // Reject URLs with userinfo component (prevents bypass like https://evil.com@allowed.com)
            if (uri.getUserInfo() != null) {
                return false;
            }

            String host = uri.getHost();
            if (host == null) {
                return false;
            }

            // Check against the allowlist
            return ALLOWED_REDIRECT_DOMAINS.contains(host.toLowerCase());

        } catch (URISyntaxException e) {
            // Malformed URL - reject
            return false;
        }
    }
}